import{_ as s,o as n,c as e,a1 as p}from"./chunks/framework.BKJzsOC1.js";const t="/assets/figure-5-multi-timeframe-spx-first.Y3EcxG92.png",b=JSON.parse('{"title":"第五章：多周期过滤与辅助确认","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/05-multi-timeframe-and-confirmation.md","filePath":"trading/intraday-entry/05-multi-timeframe-and-confirmation.md"}'),i={name:"trading/intraday-entry/05-multi-timeframe-and-confirmation.md"};function l(d,a,c,o,r,h){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="第五章-多周期过滤与辅助确认" tabindex="-1">第五章：多周期过滤与辅助确认 <a class="header-anchor" href="#第五章-多周期过滤与辅助确认" aria-label="Permalink to &quot;第五章：多周期过滤与辅助确认&quot;">​</a></h1><blockquote><p>5 分钟决定当前环境能不能做，1 分钟决定在哪里做；SPX 结构清楚时，不再等待其他市场批准。</p></blockquote><h2 id="一、每个周期只承担一项任务" tabindex="-1">一、每个周期只承担一项任务 <a class="header-anchor" href="#一、每个周期只承担一项任务" aria-label="Permalink to &quot;一、每个周期只承担一项任务&quot;">​</a></h2><p>多周期分析不是同时寻找更多信号，而是给不同周期分工：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟：判断趋势、震荡或失败突破</span></span>
<span class="line"><span>3分钟：可选的结构过渡确认</span></span>
<span class="line"><span>1分钟：寻找突破、回踩、③（回踩后再次启动的确认K）、止损与时间退出</span></span></code></pre></div><p>本文中的 <code>③</code> 不是某个指标名称，而是三步价格结构的第三步：<code>①突破关键位 → ②回踩并守住 → ③价格重新向突破方向启动</code>。做多时，③通常要向上突破回踩结构的小高点；做空时，③通常要向下跌破反抽结构的小低点。</p><p>不能让 1 分钟的一根漂亮 K 线推翻 5 分钟环境，也不能等待 5 分钟图提供精确入场，否则通常已经距离失效点过远。</p><h2 id="二、图解-5分钟环境与1分钟执行" tabindex="-1">二、图解：5分钟环境与1分钟执行 <a class="header-anchor" href="#二、图解-5分钟环境与1分钟执行" aria-label="Permalink to &quot;二、图解：5分钟环境与1分钟执行&quot;">​</a></h2><p><img src="`+t+`" alt="多周期执行与SPX优先原则"></p><p><em>教学示意：上半部分展示 5 分钟上升结构与 1 分钟突破回踩；下半部分展示 SPX 清楚和模糊时，ES 的不同作用。图中价格为构造示例。</em></p><p>完整证据链是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟形成更高高点与更高低点</span></span>
<span class="line"><span>→ 价格主要被接受在VWAP上方</span></span>
<span class="line"><span>→ SPX到达预先标记的关键位</span></span>
<span class="line"><span>→ 1分钟完成①突破、②回踩守住、③突破回踩结构并再次启动</span></span>
<span class="line"><span>→ 定义回踩结构外侧的失效点</span></span>
<span class="line"><span>→ 检查下一目标空间后建仓</span></span></code></pre></div><h2 id="三、5分钟图先回答三个问题" tabindex="-1">三、5分钟图先回答三个问题 <a class="header-anchor" href="#三、5分钟图先回答三个问题" aria-label="Permalink to &quot;三、5分钟图先回答三个问题&quot;">​</a></h2><h3 id="_1-趋势环境" tabindex="-1">1. 趋势环境 <a class="header-anchor" href="#_1-趋势环境" aria-label="Permalink to &quot;1. 趋势环境&quot;">​</a></h3><p>多头趋势通常表现为：</p><ul><li>更高高点与更高低点连续出现；</li><li>价格主要运行在 VWAP 上方；</li><li>回踩不重新接受旧区间；</li><li>上方节点仍有足够目标空间。</li></ul><p>空头趋势完全对称。</p><h3 id="_2-震荡环境" tabindex="-1">2. 震荡环境 <a class="header-anchor" href="#_2-震荡环境" aria-label="Permalink to &quot;2. 震荡环境&quot;">​</a></h3><p>以下表现说明环境尚未提供方向优势：</p><ul><li>价格反复穿越 VWAP；</li><li>开盘价和区间中轴反复被收回；</li><li>高低点结构不连续；</li><li>1 分钟突破频繁失败。</li></ul><p>震荡时中间不交易，只在区间上沿或下沿等待拒绝、失败突破或边界突破回踩。</p><h3 id="_3-失败突破" tabindex="-1">3. 失败突破 <a class="header-anchor" href="#_3-失败突破" aria-label="Permalink to &quot;3. 失败突破&quot;">​</a></h3><p>价格先离开 5 分钟区间，随后快速收回，并在再次测试边界时无法恢复突破，说明原方向被否定。此时 1 分钟用于寻找反抽或回踩失败，而不是追第一根反向 K 线。</p><h2 id="四、1分钟图只负责执行" tabindex="-1">四、1分钟图只负责执行 <a class="header-anchor" href="#四、1分钟图只负责执行" aria-label="Permalink to &quot;四、1分钟图只负责执行&quot;">​</a></h2><p>当 5 分钟环境明确后，切换到 1 分钟等待：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格到达关键位</span></span>
<span class="line"><span>→ 实体突破或快速收回</span></span>
<span class="line"><span>→ 等待回踩/反抽</span></span>
<span class="line"><span>→ ③再次启动或失败方向确认</span></span>
<span class="line"><span>→ 建仓</span></span></code></pre></div><p>1 分钟同时提供：</p><ul><li>更精确的入场位置；</li><li>回踩低点或反抽高点；</li><li>结构失效位置；</li><li>入场后 2—4 根 K 的时间止损。</li></ul><p>如果 1 分钟过于嘈杂，可以用 3 分钟确认结构已经改变，再回到 1 分钟寻找执行点。3 分钟是可选桥梁，不是每笔交易必须增加的条件。</p><h2 id="五、大小周期冲突怎样处理" tabindex="-1">五、大小周期冲突怎样处理 <a class="header-anchor" href="#五、大小周期冲突怎样处理" aria-label="Permalink to &quot;五、大小周期冲突怎样处理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>5分钟环境</th><th>1分钟信号</th><th>处理</th></tr></thead><tbody><tr><td>上升结构、VWAP上方</td><td>多头③</td><td>按主剧本评估</td></tr><tr><td>下降结构、VWAP下方</td><td>局部多头③</td><td>不追多，等待5分钟修复</td></tr><tr><td>震荡、中轴反复穿越</td><td>中间区域③</td><td>不交易，等待边界</td></tr><tr><td>5分钟收回关键位</td><td>1分钟反抽失败</td><td>可评估失败突破方向</td></tr></tbody></table><p>一分钟信号可以决定入场时机，但不能单独改变五分钟环境。</p><h2 id="六、vwap是环境过滤-不是自动反转线" tabindex="-1">六、VWAP是环境过滤，不是自动反转线 <a class="header-anchor" href="#六、vwap是环境过滤-不是自动反转线" aria-label="Permalink to &quot;六、VWAP是环境过滤，不是自动反转线&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟持续在VWAP上方、回踩守住 → 多头环境加分</span></span>
<span class="line"><span>5分钟持续在VWAP下方、反抽不过 → 空头环境加分</span></span>
<span class="line"><span>反复穿越VWAP → 震荡或尚未确认</span></span>
<span class="line"><span>1分钟突破但仍受5分钟VWAP压制 → 信号降级</span></span></code></pre></div><p>价格结构始终优先于 VWAP。VWAP 只能说明平均成交区域附近的接受状态，不能仅凭一次触碰决定买卖方向。</p><h2 id="七、spx优先-es默认不看" tabindex="-1">七、SPX优先：ES默认不看 <a class="header-anchor" href="#七、spx优先-es默认不看" aria-label="Permalink to &quot;七、SPX优先：ES默认不看&quot;">​</a></h2><p>SPX 与 ES 在正常盘中大部分时间方向高度一致。对 SPX 节点日内交易而言，ES 不是每笔交易的常驻确认项。</p><p>日常屏幕可以简化为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX 5分钟：环境</span></span>
<span class="line"><span>SPX 1分钟：执行</span></span>
<span class="line"><span>SPX节点、ORB、VWAP和前高低：位置与目标</span></span>
<span class="line"><span>ES：默认不看</span></span></code></pre></div><p>只有以下情况才临时调用 ES：</p><ol><li>盘前需要观察隔夜结构与高低点；</li><li>需要成交量或 Volume Profile；</li><li>SPX 在关键位附近反复穿越，信号难以判断；</li><li>怀疑 SPX 突破存在明显结构背离。</li></ol><p>真正值得关注的是结构级差异，而不是一两点偏差或一根 K 线的短暂领先：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX创造新高</span></span>
<span class="line"><span>但ES没有突破自己的前高</span></span>
<span class="line"><span>并开始跌破更高低点</span></span>
<span class="line"><span>→ 结构背离，视为风险警报</span></span></code></pre></div><p>如果 ES 与 SPX 同向，但 SPX 自己仍未完成收线或回踩，仍然要等待 SPX。ES 可以诊断，不能替 SPX 完成入场。</p><h2 id="八、nq和qqq怎样使用" tabindex="-1">八、NQ和QQQ怎样使用 <a class="header-anchor" href="#八、nq和qqq怎样使用" aria-label="Permalink to &quot;八、NQ和QQQ怎样使用&quot;">​</a></h2><p>NQ/QQQ 与 SPX 的成分权重差异更大，因此比 ES 提供更多科技权重强弱信息，但同样只是辅助：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX结构清楚 + NQ同向 → 可以延长正常目标</span></span>
<span class="line"><span>SPX结构清楚 + NQ稍弱但未破位 → 可缩仓或缩短目标</span></span>
<span class="line"><span>SPX向上、NQ明显反向破位 → 多头信号降级</span></span>
<span class="line"><span>NQ先动、SPX未确认 → 不追，等待SPX</span></span></code></pre></div><p>不要求所有指数每一秒完全同步。判断的是它们是否处于相同结构状态，而不是 K 线颜色是否完全一致。</p><h2 id="九、盘中执行顺序" tabindex="-1">九、盘中执行顺序 <a class="header-anchor" href="#九、盘中执行顺序" aria-label="Permalink to &quot;九、盘中执行顺序&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 先看SPX 5分钟：趋势、震荡还是失败突破？</span></span>
<span class="line"><span>2. 标记SPX关键位：节点、ORB、VWAP、前高低。</span></span>
<span class="line"><span>3. 切到SPX 1分钟：是否出现突破、回踩和③？</span></span>
<span class="line"><span>4. 写出结构失效和第一目标。</span></span>
<span class="line"><span>5. SPX清楚：直接按SPX执行，不等待ES。</span></span>
<span class="line"><span>6. SPX模糊：临时查看ES/NQ是否给出风险警报。</span></span>
<span class="line"><span>7. 辅助市场不能替代SPX确认。</span></span></code></pre></div><h2 id="十、第五章执行卡" tabindex="-1">十、第五章执行卡 <a class="header-anchor" href="#十、第五章执行卡" aria-label="Permalink to &quot;十、第五章执行卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SPX 5分钟环境：</span></span>
<span class="line"><span>SPX相对VWAP位置：</span></span>
<span class="line"><span>当前关键位：</span></span>
<span class="line"><span>SPX 1分钟触发：</span></span>
<span class="line"><span>是否完成③：</span></span>
<span class="line"><span>结构失效：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>SPX是否已经足够清楚：</span></span>
<span class="line"><span>是否真的需要查看ES/NQ：</span></span></code></pre></div><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟决定能不能做</span></span>
<span class="line"><span>1分钟决定在哪里做</span></span>
<span class="line"><span>SPX决定是否执行</span></span>
<span class="line"><span>ES/NQ只在需要时提供确认或风险警报</span></span></code></pre></div><p>最重要的一句话是：</p><blockquote><p>SPX 结构清楚时直接按 SPX 执行；只有 SPX 模糊时，才调用其他市场做诊断。</p></blockquote>`,56)])])}const P=s(i,[["render",l]]);export{b as __pageData,P as default};
